import (
	"github.com/spf13/cobra"
	"github.com/openmeterio/openmeter/cmd/jobs/internal"
)

// in your subpackage:
var Cmd = &cobra.Command{
	Use: "myjob",
	RunE: func(cmd *cobra.Command, args []string) error {
		// internal.App is already built by the root's PersistentPreRunE
		return internal.App.SomeService.DoWork(cmd.Context())
	},
}

// in cmd/jobs/main.go:
rootCmd.AddCommand(myjob.Cmd)

type Adapter interface {
	SyncStateAdapter
	entutils.TxCreator
}

type SyncState struct {
	SubscriptionID models.NamespacedID
	HasBillables   bool
	SyncedAt       time.Time
	NextSyncAfter  *time.Time
}

func (i UpsertSyncStateInput) Validate() error {
	var errs []error
	if err := i.SubscriptionID.Validate(); err != nil {
		errs = append(errs, err)
	}
	if i.HasBillables && i.NextSyncAfter == nil {
		errs = append(errs, errors.New("next sync after is required when the subscription has billables"))
	}
	return errors.Join(errs...)
}
